  ('667bbca69a5d197a321c769d', 'Десерты', 'Пирожок Вишневый', 'Обжаренный пирожок со сладкой начинкой из вишни. Возможно содержание вишневых косточек.', 650),
  ('667bbca69a5d197a321c769d', 'Напитки', 'Вода газированная', 'Очищенная питьевая вода первой категории, сильногазированная (фильтрованная и сбалансированная минералами для прекрасного вкуса).', 450),
  ('667bbca69a5d197a321c769d', 'Напитки', 'Вода негазированная', 'Очищенная питьевая вода первой категории, негазированная (фильтрованная и сбалансированная минералами для прекрасного вкуса).', 450),
