  ('5f996c81afaec06ed9baca0f', 'Роллы', 'Асшаян Темпура', 'рис, нори, креветки, такуан, омлет, зеленый лук, жареный лук, ореховый соус, юдза соус', 2990),
  ('5f996c81afaec06ed9baca0f', 'Роллы', 'Калифорния', 'Нежное мясо лосося прекрасно сочетается со сливочным сыром и рисом, а изюминку придаёт свежий огурец.', 3590),
  ('5f996c81afaec06ed9baca0f', 'Роллы', 'Фреш ролл с креветкой и шпинатом', 'Освежающий и легкий ролл без риса в составе которого вареная креветка, шпинат, соус спайси, рисовая лепешка, кляр, юдза соус, такуан.', 2990),
