  ('5f996c81afaec06ed9baca0f', 'Десерты', 'Десертный ролл с бананом', 'Десертный ролл в спринг-тесте с начинкой из спелых бананов и сладкого сыра, политый вкусной карамелью', 1390),
  ('5f996c81afaec06ed9baca0f', 'Десерты', 'Тропический десертный ролл', 'Шоколадный блин, манго, шоколадный сироп, кокосовый сироп.', 1690),
  ('5f996c81afaec06ed9baca0f', 'Дополнительное', 'Нигири с угрем', 'Аппетитный и ароматный угорь с карамельным вкусом, дополненный рассыпчатым рисом шинаки', 990),
  ('5f996c81afaec06ed9baca0f', 'Дополнительное', 'Нигири с лососем', 'Классический вариант суши, который состоит из рисовой подушки, накрытой кусочком свежего лосося. В качестве основных ингредиентов используются рис Шинаки и рыба, поэтому вкус получается чистым и очень нежным', 890),
