  ('5ecdfdbc46263855c7615b92', 'КОМБО С ГОВЯЖЬИМИ БУРГЕРАМИ🍔🍟', 'Халапеньо Бургер Комбо', 'Халапеньо Бургер, Стандартный Фри, напиток 0,5 бут, Соус', 4150),
