  ('5ecdfdbc46263855c7615b92', 'КОМБО С ГОВЯЖЬИМИ БУРГЕРАМИ🍔🍟', 'Бургер ролл Комбо', 'Бургер Ролл, Стандартный Фри, напиток 0,5 бут, Соус', 3700),
