  ('65b74c643dcd42731d0a0474', 'Донеры', 'Донер куриный в лаваше', 'Мягкий лаваш, приправленный лазджаном, который придает изысканный и бодрящий вкус блюду. Маринованное куриное мясо, соленые огурцы, лук и ароматный белый соус, прекрасно дополняющий своим вкусом', 2490),
  ('65b74c643dcd42731d0a0474', 'Донеры', 'Донер говяжий в лаваше', 'Мягкий лаваш, приправленный лазджаном, который придает изысканный и бодрящий вкус блюду. Маринованная говядина, соленые огурцы, лук и ароматный белый соус, прекрасно дополняющий своим вкусом', 2690),
  ('65b74c643dcd42731d0a0474', 'Донеры', 'Донер ассорти в лаваше', 'Мягкий лаваш, приправленный лазджаном, который придает изысканный и бодрящий вкус блюду. Маринованное ассорти из курицы и говядины, соленые огурцы, лук и ароматный белый соус, прекрасно дополняющий своим вкусом', 2690),
  ('65b74c643dcd42731d0a0474', 'Донеры', 'Донер куриный в батоне', 'Донер в хрустящем поджаристом батоне с картофелем фри. Сочная курица, соленые огурцы, лук и дополняющие своим вкусом белый и красный соусы', 2550),
  ('65b74c643dcd42731d0a0474', 'Донеры', 'Донер говяжий в батоне', 'Донер в хрустящем поджаристом батоне с картофелем фри. Сочная говядина, соленые огурцы, лук и дополняющие своим вкусом белый и красный соусы', 2690),
  ('65b74c643dcd42731d0a0474', 'Донеры', 'Донер ассорти в батоне', 'Донер в хрустящем поджаристом батоне с картофелем фри. Сочное ассорти из курицы и говядины, соленые огурцы, лук и дополняющие своим вкусом белый и красный соусы', 2690),
  ('65b74c643dcd42731d0a0474', 'Донеры', 'Донер куриный 1.5', 'Мягкий лаваш, приправленный лазджаном, который придает изысканный и бодрящий вкус блюду. Маринованная курица, соленые огурцы, лук и ароматный белый соус, прекрасно дополняющий своим вкусом', 2890),
