  ('6835cd5c34b4183c1bfeab1e', 'Мини реми макарон', 'Курт мини Реми', 'Курт мини Реми', 1090),
  ('6835cd5c34b4183c1bfeab1e', 'Мини реми макарон', 'Бородинский с сыром мини Реми', 'Хлебные крошки, сливочный сыр и солёная карамель. Тончайшее лакомство: хрустящие кусочки хлеба, нежнейший сыр и золотистая солёная карамель — сочетание, которое невозможно забыть.', 1090),
  ('6835cd5c34b4183c1bfeab1e', 'Мини реми макарон', 'Пшено с пеканом мини Реми', 'Пшено с пеканом мини Реми', 1090),
  ('6835cd5c34b4183c1bfeab1e', 'Мини реми макарон', 'Облепиха мини Реми', 'Облепиха мини Реми', 1090),
  ('6835cd5c34b4183c1bfeab1e', 'Мини реми макарон', 'Арахис-карамель мини Реми', 'Цельный арахис, белый шоколад и солёная карамель (менее сладкая версия). Для тех, кто любит контрасты: хруст арахиса, нежный белый шоколад и щепотка солёной карамели — насыщенно, но сдержанно по сладости.', 1090),
  ('6835cd5c34b4183c1bfeab1e', 'Мини реми макарон', 'Кокосовый мини Реми', 'Кокосовая паста и молочный шоколад (менее сладкая версия). Для тех, кто любит нежность без лишней сладости: сливочная кокосовая паста и молочный шоколад — мягко, тропически, с тонким послевкусием.', 1090),
  ('6835cd5c34b4183c1bfeab1e', 'Мини реми макарон', 'Корица-яблоко мини Реми', 'Пряная корица и хрустящие яблочные кусочки. Вдохновлённые уютом осени: сладкие яблоки, щедро приправленные корицей. Домашний вкус в каждой ложке.', 1090),
  ('6835cd5c34b4183c1bfeab1e', 'Мини реми макарон', 'Лимон-мак мини Реми', 'Белый шоколад, мак и лимонный крем (менее сладкая версия). Для тех, кто ценит лёгкую кислинку: нежный лимонный крем, бархат белого шоколада и деликатный хруст мака — свежее, тонкое, без лишней сладости.', 1090),
  ('6835cd5c34b4183c1bfeab1e', 'Мини реми макарон', 'Улун с розой мини Реми', 'Клубничное пюре, чай и лепестки роз. Романтика во вкусе: бархатистая клубника с лёгкой чайной терпкостью и тонким шлейфом сушёной розы. Для тех, кто ищет особенное.', 1090),
  ('6835cd5c34b4183c1bfeab1e', 'Мини реми макарон', 'Фисташка-малина мини Реми', 'Белый шоколад, фисташка и малина (менее сладкая версия). Легкая интерпретация сладкого: нежный белый шоколад, насыщенная фисташковая паста и освежающая малина — без лишней приторности.', 1090),
  ('6835cd5c34b4183c1bfeab1e', 'Мини реми макарон', 'Фисташка-улун мини Реми', 'Фисташковое пралине с молочным улуном. Бархатная паста из фисташек с изысканным послевкусием молочного чая улун. Мягко, глубоко и по-настоящему утончённо.', 1090),
  ('6835cd5c34b4183c1bfeab1e', 'Мини реми макарон', 'Шоколад-орех мини Реми', 'Тёмный шоколад, дроблёный арахис и Nutella (менее сладкая версия). Для тех, кто любит с характером: плотный тёмный шоколад, хруст арахиса и капля Nutella — насыщенно, но сдержанно по сладости.', 1090),
  ('6835cd5c34b4183c1bfeab1e', 'Мини реми макарон', 'Чизкейк-клубника мини Реми', 'Белый шоколад, клубничное пюре и кусочек чизкейка (менее сладкая версия). Для тех, кто ищет баланс: нежный белый шоколад, освежающее клубничное пюре и кусочек настоящего чизкейка — сливочно, ягодно, но без приторности.', 1090),
  ('6835cd5c34b4183c1bfeab1e', 'Реми макарон', 'Фисташка-малина макарон Реми', 'Белый шоколад, фисташка и малина (менее сладкая версия). Легкая интерпретация сладкого: нежный белый шоколад, насыщенная фисташковая паста и освежающая малина — без лишней приторности.', 1790),
