  ('656709cd2a98c764f413dca0', 'СТЕЙКИ 🥩 ', 'Ти-бон стейк', 'Стейк из говядины, разделен Т-образной косточкой.', 9250),
  ('656709cd2a98c764f413dca0', 'СТЕЙКИ 🥩 ', 'Рибай стейк', 'Самый популярный и известный стейк из говядины.', 7800),
