  ('656709cd2a98c764f413dca0', 'СТЕЙКИ 🥩 ', 'Филе индейки под сыром', 'Стейк индейки - это нежное мясо грудки индейки, приготавливается в Хоспер печи, под сыром Моцарелла.', 4000),
  ('656709cd2a98c764f413dca0', 'СТЕЙКИ 🥩 ', 'Стейк из цыплёнка', 'Маринованное сочное мясо цыплёнка без косточек.', 3400),
  ('656709cd2a98c764f413dca0', 'СТЕЙКИ 🥩 ', 'Филе курицы', 'Нежная куриная грудка, приправленная специями и травами.', 2550),
  ('656709cd2a98c764f413dca0', 'СТЕЙКИ 🥩 ', 'Стейк из семги', 'Нежная красная рыба, запеченная в Хоспер печи', 7100),
