  ('68d533711f1d9b15a22264ca', 'КОМБО 🍱', 'Комбо 3', 'Курочка Сеул (3 шт.), фирменный рис, пита (6 шт.), салат морковь ча (3 шт.), салат кимчи (3 шт.), острый соус (3 шт.), чесночный соус (3 шт.), морс домашнего приготовления (3 л)', 21950),
  ('68d533711f1d9b15a22264ca', 'САЛАТЫ, ПИТА, СОУСЫ 🥗🫓', 'Пита', 'Свежайшая пита с добавлением отрубей', 300),
  ('68d533711f1d9b15a22264ca', 'САЛАТЫ, ПИТА, СОУСЫ 🥗🫓', 'Фирменный рис', 'Авторский рис с добавлением дикого риса, кукурузы, и заправленный специями', 650),
  ('68d533711f1d9b15a22264ca', 'САЛАТЫ, ПИТА, СОУСЫ 🥗🫓', 'Салат морковь ча', 'Корейский салат морковь ча средней остроты', 650),
  ('68d533711f1d9b15a22264ca', 'САЛАТЫ, ПИТА, СОУСЫ 🥗🫓', 'Салат кимчи', 'Корейский салат кимчи по-южнокорейскому рецепту', 650),
  ('68d533711f1d9b15a22264ca', 'САЛАТЫ, ПИТА, СОУСЫ 🥗🫓', 'Красный острый соус', 'Классический острый соус, приготовленный на основе томатов', 400),
  ('68d533711f1d9b15a22264ca', 'САЛАТЫ, ПИТА, СОУСЫ 🥗🫓', 'Белый чесночный соус', 'Соус, главным компонентом которого является чеснок, используемый для приготовления различных блюд всемирной кухни. Имеет выразительный чесночный вкус', 400),
  ('68d533711f1d9b15a22264ca', 'НАПИТКИ🥤', 'Домашний морс 0,5 л', 'Фирменный морс собственного приготовления', 650),
