  ('5d83ad15c5b379474012832a', 'Напитки', '*Мохито Клубника', 'Лёгкий, освежающий и по-летнему яркий. Настроение — chill. 500 мл', 1500),
  ('5d83ad15c5b379474012832a', 'Напитки', '*Морс Черная Смородина', 'Густой вкус и мощный заряд свежести. Настоящая ягодная сила. 500 мл', 1500),
  ('5d83ad15c5b379474012832a', 'Напитки', '*Морс Клюква', 'Бодрит с первого глотка. Натуральная кислинка и чистая энергия ягод. 500 мл', 1500),
  ('5d83ad15c5b379474012832a', 'Напитки', '*Морс Гранат', 'Насыщенный, сочный и немного дерзкий. Вкус, который запоминается. 500 мл', 1500),
  ('5d83ad15c5b379474012832a', 'Напитки', 'Coca-Cola zero M', 'Освежающий газированный напиток', 1200),
  ('5d83ad15c5b379474012832a', 'Десерты', 'Чизкейк', 'Классический ванильный вкус и идеальное завершение любого праздничного ужина.', 3450),
  ('5d83ad15c5b379474012832a', 'Десерты', 'Малина-Фисташка', 'Яркий и ароматный десерт: нежный крем-чиз с фисташковым кремом на песочном корже, щедро усыпан цельными ягодами малины и декорирован фисташкой.', 3450),
  ('5d83ad15c5b379474012832a', 'Десерты', 'Таяки с вишнёвой начинкой', 'Японский десерт в виде рыбки с вишневой начинкой, поданный с соусами соленая карамель и зеленый чай. Нежная сладость вишни в сочетании с карамелью и освежающим чаем.', 1850),
  ('5d83ad15c5b379474012832a', 'Десерты', 'Таяки с шоколадной начинкой', 'Японский десерт в виде рыбки с шоколадной начинкой, поданный с соусами соленая карамель и зеленый чай. Нежный шоколад в сочетании с карамелью и освежающим чаем.', 1850),
  ('5d83ad15c5b379474012832a', 'Допы', 'Васаби', 'Жанып тұратын дәмі бар жапондық васаби дәмдеуіші. Әдетте суши, сашими және роллдарға қосылып беріледі.', 350),
  ('5d83ad15c5b379474012832a', 'Допы', 'Имбирь', 'Хош иісті дәмдеуіш, қанық және сергітетін дәмі бар. Тағамдарға жеңіл ащылық пен ерекше дәм беру үшін қолданылады.', 350),
  ('5d83ad15c5b379474012832a', 'Допы', 'Соевый соус', 'Азиялық асхананың дәстүрлі соусы, қанық дәмі мен жеңіл тұздығы бар. Минералдар, витаминдер және аминқышқылдарына бай.', 350),
  ('5d83ad15c5b379474012832a', 'Допы', 'Соус унаги', 'Қою соус, соя тұздығы мен тәтті күріш шарабының үйлесімі. Тағамға қанық дәм мен жеңіл тәтті-құмартпа хош иіс береді.', 450),
  ('5d83ad15c5b379474012832a', 'Допы', 'Ореховый соус', 'Хош иісті, қанық жаңғақ дәмі бар соус. Ет, көкөністер мен кеспемен үйлеседі.', 450),
  ('5d83ad15c5b379474012832a', 'Допы', 'Розовый соус', 'Жұмсақ құрылымды, жеңіл ащылығы бар соус. Тәтті және хош иісті реңктері үйлескен дәмімен ерекшеленеді.', 450),
