  ('6436998d7ea3611685d61ead', 'Напитки ', 'Натахтари Фейхоа 0,5', 'Вкусный освежающий лимонад с насыщенными вкусами.', 1599),
  ('6436998d7ea3611685d61ead', 'Напитки ', 'Borjomi 0,5', 'Легендарная минеральная вода вулканического происхождения, которой по природным меркам уже более 1500 лет.', 1580),
