  ('67ea9819d1fe385b18aedbf6', 'Spring Special', 'Chili beef smash burger', 'Пикантный бургер с котлетой из говяжьего фарша с добавлением специй, сыром чеддер, чипотле майонезом, луком и маринованным халапеньо в булочке бриошь', 4000),
  ('67ea9819d1fe385b18aedbf6', 'Spring Special', 'Arrabbiata burger', 'Свежий и сочный бургер с говяжьей котлетой, моцареллой, соусом арабьята, песто с базиликом и майонезом с харрисой в булочке бриошь', 4800),
  ('67ea9819d1fe385b18aedbf6', 'Акции', 'Машрум+Red Bull  Wolt 2026', NULL, 5900),
  ('67ea9819d1fe385b18aedbf6', 'Акции', 'Чизбургер +Red Bull 250 ml Wolt 2026', NULL, 5000),
  ('67ea9819d1fe385b18aedbf6', 'Акции', 'Чизбургер', 'Смаш котлета из мраморной говядины, маринованные огурцы с укропом, лук, сыр чеддер, горчица, кетчуп', 3000),
  ('67ea9819d1fe385b18aedbf6', 'Акции', 'Классический  бургер', 'Двойная смаш котлета из мраморной говядины, салат айсберг, маринованные огурцы с укропом, помидор, кетчуп, сыр чеддер, домашний майонез', 4100),
  ('67ea9819d1fe385b18aedbf6', 'Бургеры', 'Машрум бургер', 'Смаш котлета из мраморной говядины, грибное конфи, красный лук, маринованные огурцы, сыр чеддер, соус айоли и заправка коул слоу', 3900),
  ('67ea9819d1fe385b18aedbf6', 'Бургеры', 'Бургер Дижонская курочка', 'Куриное филе в панировке, горчично-медовый соус, жареные грибы, огурцы, домашний майонез, жареный лук', 3500),
  ('67ea9819d1fe385b18aedbf6', 'Бургеры', 'Бургер Харисса', 'Двойная смаш котлета из мраморной говядины, соус Харисса, помидоры, огурцы с укропом, конфитюр из красного лука, айсберг, сыр чеддер', 4500),
  ('67ea9819d1fe385b18aedbf6', 'Бургеры', 'Вегетарианский бургер', 'Бриошь, вегетарианская котлета, моцарелла,соус терияки, домашний майонез и горчица', 3400),
  ('67ea9819d1fe385b18aedbf6', 'Бургеры', 'Трипл смаш бургер', 'Тройная котлета из мраморной говядины, сыр чеддер, лук, горчичный соус, криспи лук', 5300),
  ('67ea9819d1fe385b18aedbf6', 'Бургеры', 'Очень сырный бургер', 'Двойная смаш котлета из мраморной говядины, сыр моцарелла, салат айсберг, сыр чеддер, соус блю чиз', 4400),
  ('67ea9819d1fe385b18aedbf6', 'Бургеры', 'Бургер Оклахома брискет смэш', 'Смаш котлета из мраморной говядины, томленая говядина с соусом барбекю и дижонской горчицей, сыр чеддер, соус айоли, маринованный  красный лук', 4500),
  ('67ea9819d1fe385b18aedbf6', 'Бургеры', 'Двойной чизбургер с говяжьим беконом', 'Двойная смаш котлета из мраморной говядины, соус для бургера, сладкие огурцы, сыр чеддер,говяжий бекон, помидоры, хрустящий лук', 4800),
  ('67ea9819d1fe385b18aedbf6', 'Бургеры', 'Халапеньо бургер', 'Двойная смаш котлета из мраморной говядины, острый соус, перец халапеньо, салат айсберг, сыр чеддер, маринованный лук, домашний майонез', 4100),
  ('67ea9819d1fe385b18aedbf6', 'Комбо', 'Детский Бокс', 'Джуниор бургер, картофель фри, сок Piko, игрушка', 4400),
  ('67ea9819d1fe385b18aedbf6', 'Комбо', 'Классическое комбо', 'Классический бургер, картофель фри, холодный красный чай, соус', 5100),
  ('67ea9819d1fe385b18aedbf6', 'Комбо', 'Комбо Дижонская курочка', 'Бургер Дижонская курочка, картофель фри, холодный красный чай, соус', 4800),
  ('67ea9819d1fe385b18aedbf6', 'Комбо', 'Комбо Халапеньо', 'Бургер Халапеньо, картофель фри, холодный красный чай, соус', 5200),
  ('67ea9819d1fe385b18aedbf6', 'Закуски', 'Наггетсы', 'Блюдо из филе куриной грудки в хрустящей панировке, обжаренной в масле', 1900),
  ('67ea9819d1fe385b18aedbf6', 'Закуски', 'Батат-фри', 'Сладкий батат во фритюре', 2000),
  ('67ea9819d1fe385b18aedbf6', 'Закуски', 'Коул слоу', 'Красная капуста, белокочанная капуста, морковь, белый соус', 1500),
  ('67ea9819d1fe385b18aedbf6', 'Закуски', 'Криспи стрипсы', 'Нежные кусочки курочки в панировке, обжаренные до золотистой корочки. Простая закуска, которая пользуется популярностью в различных кухнях по всему миру. Имеют легкую остроту', 2800),
  ('67ea9819d1fe385b18aedbf6', 'Гарниры', 'Луковые кольца', 'Аппетитная закуска или гарнир, приготовленная из лука в панировке, обжаренного до хрустящей корочки', 1500),
  ('67ea9819d1fe385b18aedbf6', 'Гарниры', 'Картофель дольками', 'Картофель, обжаренный до золотистой корочки, обладает богатым и насыщенным вкусом и отлично сочетается с соусами и специями', 1300),
  ('67ea9819d1fe385b18aedbf6', 'Гарниры', 'Картофель рифленый', 'Рифленый картофель, обжаренный до золотистой корочки, хрустящий снаружи и мягкий внутри.', 1300),
  ('67ea9819d1fe385b18aedbf6', 'Гарниры', 'Картофель фри', '"Картофель, обжаренный до золотистой корочки, хрустящий снаружи и мягкий внутри. Является популярным гарниром или закуской, которая отлично сочетается с различными соусами"', 1300),
  ('67ea9819d1fe385b18aedbf6', 'Соусы', 'Соус Горчичный', 'Обладает остро-пикантным вкусом и используется в различных кулинарных блюдах. Отлично подходит в качестве приправы к мясным блюдам, бутербродам или соусу для салатов. Он придает яркий вкус и аромат, а также добавляет пикантность', 500),
  ('67ea9819d1fe385b18aedbf6', 'Соусы', 'Соус Кетчуп', 'Классический и универсальный соус, приготовленный на основе томатов', 500),
  ('67ea9819d1fe385b18aedbf6', 'Соусы', 'Соус Домашний майонез', 'Классический соус, известный своей гладкой и кремообразной текстурой, богатым и насыщенным вкусом. Этот соус обладает широкой популярностью и часто используется в мировой кулинарии', 500),
  ('67ea9819d1fe385b18aedbf6', 'Соусы', 'Соус Медово-горчичный', 'Классический соус, который идеально подходит для мясных и рыбных блюд, а также овощей и бутербродов', 500),
  ('67ea9819d1fe385b18aedbf6', 'Соусы', 'Соус Чесночный', 'Имеет широкую популярность, благодаря своей универсальности и вкусовому богатству. Он придает блюдам особый аромат и вкус, делая их приятными для гурманов и любителей пикантности', 500),
  ('67ea9819d1fe385b18aedbf6', 'Соусы', 'Соус Сырный', '"Ароматный и нежный соус, который придаёт блюдам богатый вкус и насыщенную текстуру. Он идеально сочетается с различными закусками, грилем, сэндвичами и салатами"', 500),
  ('67ea9819d1fe385b18aedbf6', 'Соусы', 'Соус Блючиз', 'Имеет ярко выраженный вкус голубого сыра и обладает приятной сливочной консистенцией', 500),
  ('67ea9819d1fe385b18aedbf6', 'Дополнительно', 'Доп. сыр', NULL, 500),
  ('67ea9819d1fe385b18aedbf6', 'Дополнительно', 'Доп. халапеньо', 'Острая добавка, которая придаёт пикантность различным блюдам', 500),
  ('67ea9819d1fe385b18aedbf6', 'Дополнительно', 'Дополнительная Экстра котлета', 'Дополнительная говяжья котлета', 1700),
  ('67ea9819d1fe385b18aedbf6', 'Десерты', 'Печенье с грецким орехом', 'Яйца, мука, грецкий орех, сахар, белый шоколад, сливочное масло, шоколад молочный, ваниль', 2000),
