  ('624464aebc135d887c471a16', 'Хлеб', 'Лепешка 100 г', 'Лепешка', 100),
  ('6994030f22081198b8156f77', 'Акции', 'Плов Ханский на 5 персон', 'Ханский плов на 5 персон — щедрое праздничное блюдо из рассыпчатого риса, нежной говядины, моркови и ароматных специй. Сытный, насыщенный и идеально подходит для большой компании.', 14390),
  ('6994030f22081198b8156f77', 'Плов', 'Плов Самарканд', 'Самаркандский плов — традиционное восточное блюдо из рассыпчатого риса, сочной говядины и сладкой моркови. Готовится с ароматными специями, имеет мягкий, насыщенный вкус и отлично утоляет голод.', 2890),
  ('6994030f22081198b8156f77', 'Комбо', 'Комбо плов Самарканд', 'Полноценный обед в одном наборе: Самаркандский плов, освежающий напиток, на выбор салат ачичук или хрустящая тандырная самса. Сытно, вкусно и удобно.', 4350),
  ('6994030f22081198b8156f77', 'Самса', 'Самса с говядиной', 'Самса с говядиной — румяная восточная выпечка с сочной начинкой из отборной говядины и ароматных специй. Сытная, насыщенная и аппетитная.', 890),
  ('6994030f22081198b8156f77', 'Салаты', 'Ачичук', 'Освежающий салат из нарезанных томатов и лука, приправленный специями. Отлично сочетается с пловом и самсой.', 890),
  ('6994030f22081198b8156f77', 'Напитки', 'Айран фреш', 'Холодный, безалкогольный кисломолочный напиток', 495),
  ('6994030f22081198b8156f77', 'Напитки', 'Fuse tea Манго-Ромашка 0.5 l', 'Легкий чайный вкус с нотками манго и нежной ромашки. Освежает и расслабляет', 695),
  ('6994030f22081198b8156f77', 'Напитки', 'Fuse tea Персик 0.5 l', 'Нежный вкус холодного чая с ароматом спелого персика. Освежает, утоляет жажду и дарит приятное послевкусие.', 695),
  ('6994030f22081198b8156f77', 'Напитки', 'Вода 0.5 l', 'Чистая питьевая вода без газа. Лёгкая, освежающая, идеально к еде.', 545),
  ('6994030f22081198b8156f77', 'Напитки', 'Fuse tea Ягоды 0.5 l', 'Освежающий холодный чай с ярким ягодным вкусом. Лёгкий, ароматный и в меру сладкий — отличное дополнение к любому блюду или перекусу.', 695),
  ('6994030f22081198b8156f77', 'Напитки', 'Coca cola ж/б', 'Вкус Coca-Cola без сахара. Максимум свежести, минимум калорий — и всё это в стильной банке.', 695),
  ('6994030f22081198b8156f77', 'Напитки', 'Coca cola ZERO', 'Та самая классика — в удобной охлаждённой банке. Идеальный формат для takeaway.', 695),
  ('6994030f22081198b8156f77', 'Напитки', 'Sprite 0.5 l', 'Лимонно-лаймовый газированный напиток с кристальной свежестью. Отлично утоляет жажду.', 695),
  ('6994030f22081198b8156f77', 'Напитки', 'Fuse tea Манго-Ананас 0.5 l', 'Экзотическое сочетание манго и ананаса на основе холодного чая. Тропический вкус и мягкое расслабление.', 695),
  ('6994030f22081198b8156f77', 'Напитки', 'Coca cola 0.5 l', 'Классическая Coca-Cola — освежающая, шипучая, с тем самым легендарным вкусом.', 695),
  ('6994030f22081198b8156f77', 'Напитки', 'Fanta 0.5 l', 'Яркий цитрусовый вкус апельсина и весёлые пузырьки — настроение в каждой бутылке.', 695),
